778	static bool test_read_vector_case(FILE *fp, test_vec_case *vc) {
779	    char line[2048];
780	    memset(vc, 0, sizeof(*vc));
781	    while (fgets(line, sizeof(line), fp)) {
782	        char *p = test_trim_line(line);
783	        if (!p[0] || p[0] == '#') continue;
784	        if (sscanf(p, "case %95s %d %d %511s",
785	                   vc->id, &vc->ctx, &vc->nsteps, vc->prompt_path) == 4) {
786	            TEST_ASSERT(vc->nsteps > 0 && vc->nsteps <= TEST_VEC_MAX_STEPS);
787	            return true;
788	        }
789	        TEST_ASSERT(!"unexpected line before vector case");
790	    }
791	    return false;
792	}
