794	static bool test_fill_vector_case(FILE *fp, test_vec_case *vc) {
795	    char line[2048];
796	    int step_index = -1;
797	    int top_index = 0;
798	
799	    while (fgets(line, sizeof(line), fp)) {
800	        char *p = test_trim_line(line);
801	        if (!p[0] || p[0] == '#') continue;
802	        if (!strcmp(p, "end")) return true;
803	
804	        if (!strncmp(p, "step ", 5)) {
805	            char hex[TEST_VEC_MAX_TOKEN_BYTES * 2 + 2];
806	            int ntop = 0;
807	            if (sscanf(p, "step %d %257s %d", &step_index, hex, &ntop) != 3) {
808	                TEST_ASSERT(!"bad vector step line");
809	                return false;
810	            }
811	            TEST_ASSERT(step_index >= 0 && step_index < vc->nsteps);
812	            TEST_ASSERT(ntop >= 0 && ntop <= TEST_VEC_MAX_TOP);
